tinymce.PluginManager.add('charts', function(editor, url) {
    editor.ui.registry.addIcon('charts', '<?xml version="1.0" ?><svg baseProfile="tiny" height="24px" id="Layer_1" version="1.2" viewBox="0 0 24 24" width="24px" xml:space="preserve" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink"><path d="M14,4c0-1.105-0.896-2-2-2s-2,0.895-2,2v12h4V4z"/><path d="M19,8c0-1.105-0.896-2-2-2s-2,0.895-2,2v8h4V8z"/><path d="M9,11c0-1.105-0.896-2-2-2s-2,0.895-2,2v5h4V11z"/><path d="M19,19H5c-0.553,0-1,0.447-1,1s0.447,1,1,1h14c0.553,0,1-0.447,1-1S19.553,19,19,19z"/></svg>');

    var openDialog = function () {
        var cid = editor.getParam('content_id');
        var ctype = editor.getParam('content_type');
        var module_code = editor.getParam('module_code');
        var query = '?cid='+cid+'&ctype='+ctype+'&moduleCode='+module_code;
        return editor.windowManager.openUrl({
            url: tinymce.baseURL + '/plugins/charts/scripts/charts.php'+query,
            title: 'Charts',
            width: 740,
            height: 450,
        });
    };

    editor.ui.registry.addButton('charts', {
        tooltip: 'Charts',
        icon: 'charts',
        onAction: function () {
            // Open window
            openDialog();
        }

    });

    // Adds a menu item, which can then be included in any menu via the menu/menubar configuration
    editor.ui.registry.addMenuItem('charts', {
        text: 'Charts',
        icon: 'charts',
        onAction: function () {
            // Open window
            openDialog();
        }
    });
});